const response = $input.item.json;
const text = response.content[0].text;

let skill;
try {
  // Remove markdown code blocks se existirem
  const cleaned = text.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
  skill = JSON.parse(cleaned);
} catch (e) {
  throw new Error('Skill Factory retornou JSON inválido: ' + text.substring(0, 200));
}

// Garante status ativo
skill.status = 'ativo';
skill.gerado_em = new Date().toISOString();
skill.gerado_por = 'skill-factory-agent';
skill.versao = 1;

return [{ json: skill }];
